import{_ as s,o as i,c as e,a2 as n}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"使用公开评价、Issue、文档与更新日志验证问题","description":"","frontmatter":{},"headers":[],"relativePath":"03-interaction-design/notes/validation/01-public-reviews-issues-docs-changelogs.md","filePath":"03-interaction-design/notes/validation/01-public-reviews-issues-docs-changelogs.md","lastUpdated":1784248569000}'),l={name:"03-interaction-design/notes/validation/01-public-reviews-issues-docs-changelogs.md"};function t(r,a,p,d,h,o){return i(),e("div",null,[...a[0]||(a[0]=[n(`<h1 id="使用公开评价、issue、文档与更新日志验证问题" tabindex="-1">使用公开评价、Issue、文档与更新日志验证问题 <a class="header-anchor" href="#使用公开评价、issue、文档与更新日志验证问题" aria-label="Permalink to &quot;使用公开评价、Issue、文档与更新日志验证问题&quot;">​</a></h1><p>公开评价、开源 Issue、帮助文档和更新日志可以为个人学习提供真实问题线索、预期规则和版本变化证据。它们不能自动代表全部用户，也不能单独证明原因与发生率。可靠方法是限定版本与任务、结构化编码证据，并通过产品复现、文档或实现资料交叉验证。</p><h2 id="四类资料的能力边界" tabindex="-1">四类资料的能力边界 <a class="header-anchor" href="#四类资料的能力边界" aria-label="Permalink to &quot;四类资料的能力边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>资料</th><th>主要价值</th><th>典型偏差或限制</th></tr></thead><tbody><tr><td>应用商店、论坛与社交评价</td><td>用户语言、具体失败场景、情绪和长期问题线索</td><td>自选择偏差、版本不明、无法核实环境、重复传播</td></tr><tr><td>GitHub Issue/讨论</td><td>复现步骤、环境、维护者确认、代码和修复关联</td><td>开源用户不等于全部用户；问题可能过期或项目特有</td></tr><tr><td>官方帮助与规则文档</td><td>产品预期、术语、资格、流程和恢复说明</td><td>文档可能落后；不能证明实现符合说明</td></tr><tr><td>更新日志与发布说明</td><td>版本、功能变化、修复与迁移范围</td><td>常省略已知问题、实验组和实现细节</td></tr></tbody></table><p>公开资料适合发现“应检查什么”。是否在当前版本、角色和设备上成立，需要实际复现。</p><h2 id="证据链" tabindex="-1">证据链 <a class="header-anchor" href="#证据链" aria-label="Permalink to &quot;证据链&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S[&quot;公开问题线索&quot;] --&gt; C[&quot;编码任务、环境与现象&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[&quot;核对官方规则和版本&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; R[&quot;在当前产品复现&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    R --&gt; H[&quot;形成机制假设&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    H --&gt; V[&quot;补充日志、实现或多源证据&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    V --&gt; O[&quot;结论、范围与未知项&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>无法复现不表示反馈虚假。它可能依赖旧版本、地区、账户、数据、渐进发布或已修复。结论应写“在指定条件下未复现”，而不是“问题不存在”。</p><h2 id="建立检索范围" tabindex="-1">建立检索范围 <a class="header-anchor" href="#建立检索范围" aria-label="Permalink to &quot;建立检索范围&quot;">​</a></h2><h3 id="固定知识问题" tabindex="-1">固定知识问题 <a class="header-anchor" href="#固定知识问题" aria-label="Permalink to &quot;固定知识问题&quot;">​</a></h3><p>先写明确问题，例如：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>当前 Web 版在网络中断后，是否保留未提交表单？</span></span>
<span class="line"><span>移动端通知深链登录后是否返回原任务？</span></span>
<span class="line"><span>批量导入的“完成”指上传完成还是处理完成？</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>“找找大家有什么不满”会产生大量无法比较的情绪材料。</p><h3 id="固定时间与版本" tabindex="-1">固定时间与版本 <a class="header-anchor" href="#固定时间与版本" aria-label="Permalink to &quot;固定时间与版本&quot;">​</a></h3><ul><li>产品、平台、版本或观察日期；</li><li>更新前后窗口；</li><li>语言、地区和账户类型；</li><li>已知实验、功能开关或分阶段发布。</li></ul><p>评价发布时间不等于问题发生时间。正文中要分别记录。</p><h3 id="使用多个术语" tabindex="-1">使用多个术语 <a class="header-anchor" href="#使用多个术语" aria-label="Permalink to &quot;使用多个术语&quot;">​</a></h3><p>搜索用户用语、产品术语、错误文本、状态名和对象名。例如搜索“丢失草稿”“刷新后清空”“未保存”“autosave”，但不能把不同机制的结果强行归为同一问题。</p><h2 id="结构化证据记录" tabindex="-1">结构化证据记录 <a class="header-anchor" href="#结构化证据记录" aria-label="Permalink to &quot;结构化证据记录&quot;">​</a></h2><div class="language-markdown vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 证据 ID：PUB-001</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 来源类型：Issue / 评价 / 文档 / 更新日志</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 原始链接：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 发布时间与产品版本：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 用户角色/设备/环境：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 任务与入口：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 可观察现象：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 影响与恢复：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 维护者或官方确认：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 当前复现结果：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 相关证据：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 可信范围与未知项：</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>只摘取完成分析所需的短句并链接原文，避免复制长篇受版权保护内容。公开用户名、邮箱、订单和附件也可能含个人信息，笔记中应去标识化。</p><h2 id="编码问题而不是计算情绪" tabindex="-1">编码问题而不是计算情绪 <a class="header-anchor" href="#编码问题而不是计算情绪" aria-label="Permalink to &quot;编码问题而不是计算情绪&quot;">​</a></h2><h3 id="任务编码" tabindex="-1">任务编码 <a class="header-anchor" href="#任务编码" aria-label="Permalink to &quot;任务编码&quot;">​</a></h3><p>把资料归入真实任务：登录、创建、支付、同步、导出、取消。相同情绪词可能对应不同任务，不应合并。</p><h3 id="现象编码" tabindex="-1">现象编码 <a class="header-anchor" href="#现象编码" aria-label="Permalink to &quot;现象编码&quot;">​</a></h3><p>使用可观察类别：</p><ul><li>无法找到入口；</li><li>操作后无反馈；</li><li>数据丢失或重复；</li><li>权限或规则不清；</li><li>性能慢或超时；</li><li>错误不可恢复；</li><li>键盘、缩放或辅助技术不可用。</li></ul><h3 id="环境编码" tabindex="-1">环境编码 <a class="header-anchor" href="#环境编码" aria-label="Permalink to &quot;环境编码&quot;">​</a></h3><p>平台、版本、网络、角色、语言、数据量和对象状态。缺失就标记未知，不猜测。</p><h3 id="结果编码" tabindex="-1">结果编码 <a class="header-anchor" href="#结果编码" aria-label="Permalink to &quot;结果编码&quot;">​</a></h3><p>成功、失败、部分成功、放弃、误以为成功或结果未知。评价星级不能代替任务结果。</p><h2 id="证据强度" tabindex="-1">证据强度 <a class="header-anchor" href="#证据强度" aria-label="Permalink to &quot;证据强度&quot;">​</a></h2><p>可按以下层级记录，但不要把层级当统计代表性：</p><ol><li>单条无环境描述的公开评价：问题线索。</li><li>多条独立资料描述相同任务与现象：重复线索。</li><li>有版本、步骤、数据和维护者确认的 Issue：较强复现线索。</li><li>当前版本按相同条件可复现：当前实现事实。</li><li>请求、日志、代码或规则解释机制：机制证据。</li><li>有明确总体、分母与采样的性能数据：范围与频率证据。</li></ol><p>十条相似评论仍可能来自同一传播事件，不能直接计算“发生率 10%”。</p><h2 id="文档与实现差异" tabindex="-1">文档与实现差异 <a class="header-anchor" href="#文档与实现差异" aria-label="Permalink to &quot;文档与实现差异&quot;">​</a></h2><p>建立双栏：</p><table tabindex="0"><thead><tr><th>官方预期</th><th>当前实现</th></tr></thead><tbody><tr><td>帮助说明失败后草稿保留 30 天</td><td>浏览器刷新后字段为空</td></tr><tr><td>发布说明称 v4.2 修复离线恢复</td><td>v4.2.1 的 Android 仍可复现</td></tr></tbody></table><p>差异可能来自文档落后、修复不完整、平台差异或复现条件错误。先保存证据，再提出解释。</p><h2 id="完整案例-验证-上传成功但找不到导入结果" tabindex="-1">完整案例：验证“上传成功但找不到导入结果” <a class="header-anchor" href="#完整案例-验证-上传成功但找不到导入结果" aria-label="Permalink to &quot;完整案例：验证“上传成功但找不到导入结果”&quot;">​</a></h2><h3 id="具体资料输入" tabindex="-1">具体资料输入 <a class="header-anchor" href="#具体资料输入" aria-label="Permalink to &quot;具体资料输入&quot;">​</a></h3><p>在 2026-06 至 2026-07 收集到：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PUB-01：应用商店评价称“CSV 显示完成，成员没有出现”，平台 Android，版本未知。</span></span>
<span class="line"><span>PUB-02：GitHub Issue #842 给出 Web v5.3、10,000 行 CSV，上传后刷新任务消失。</span></span>
<span class="line"><span>DOC-01：官方帮助写“上传完成后在后台处理，可从导入历史查看”。</span></span>
<span class="line"><span>LOG-01：v5.3 更新日志写“新增可恢复导入任务”。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="编码" tabindex="-1">编码 <a class="header-anchor" href="#编码" aria-label="Permalink to &quot;编码&quot;">​</a></h3><table tabindex="0"><thead><tr><th>ID</th><th>任务</th><th>现象</th><th>环境</th><th>初始解释</th></tr></thead><tbody><tr><td>PUB-01</td><td>导入成员</td><td>完成反馈与最终数据不一致</td><td>Android、版本未知</td><td>阶段反馈或同步问题</td></tr><tr><td>PUB-02</td><td>导入成员</td><td>刷新后无法恢复</td><td>Web v5.3、大文件</td><td>任务入口或持久化问题</td></tr><tr><td>DOC-01</td><td>导入成员</td><td>预期异步且可恢复</td><td>当前官方文档</td><td>规则基线</td></tr><tr><td>LOG-01</td><td>导入成员</td><td>声称新增恢复能力</td><td>v5.3</td><td>版本变化</td></tr></tbody></table><h3 id="当前版本复现" tabindex="-1">当前版本复现 <a class="header-anchor" href="#当前版本复现" aria-label="Permalink to &quot;当前版本复现&quot;">​</a></h3><p>固定条件：Web v5.3.1、项目管理员、<code>members-10000.csv</code>、其中 10 行错误、400 ms RTT。</p><ol><li>从成员页上传文件，传输到 100% 后显示“上传完成，正在处理”。</li><li>页面提供任务 ID <code>IMP-8801</code> 和“可以离开”说明。</li><li>刷新后仍在任务详情，状态为“处理中”。</li><li>返回成员页，从“导入历史”找到 <code>IMP-8801</code>。</li><li>处理结束为 9,990 成功、10 失败，可下载错误报告。</li></ol><p>输出：PUB-02 在 v5.3.1 指定条件下未复现；LOG-01 的恢复能力在 Web 当前版本可见。PUB-01 因平台和版本不同不能被否定，需要 Android 同条件验证。</p><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>将网络在上传 60% 时断开：界面显示上传失败并允许重试，未创建导入任务。将解析服务模拟为失败：任务仍可恢复，状态为“处理失败”，说明没有写入成员。两者证明“上传失败”和“处理失败”是不同问题编码。</p><h3 id="额外证据" tabindex="-1">额外证据 <a class="header-anchor" href="#额外证据" aria-label="Permalink to &quot;额外证据&quot;">​</a></h3><p>网络记录显示任务创建只在完整上传后发生；任务 ID 刷新后由服务端读取。没有总体用户与版本分布，因此不能据两条公开反馈估计发生率。</p><h2 id="从公开资料生成验证任务" tabindex="-1">从公开资料生成验证任务 <a class="header-anchor" href="#从公开资料生成验证任务" aria-label="Permalink to &quot;从公开资料生成验证任务&quot;">​</a></h2><p>将每条线索转换为：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>给定：角色、平台、版本、数据和前置状态</span></span>
<span class="line"><span>当：执行可重复步骤</span></span>
<span class="line"><span>则：观察对象、业务和用户可见结果</span></span>
<span class="line"><span>并且：刷新、返回或失败后仍可确认</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>若资料缺少数据，使用最小、上限、特殊字符和旧对象状态等安全测试组合，不在生产账户制造破坏性结果。</p><h2 id="常见错误与修正" tabindex="-1">常见错误与修正 <a class="header-anchor" href="#常见错误与修正" aria-label="Permalink to &quot;常见错误与修正&quot;">​</a></h2><ul><li>按星级判断可用性：回到具体任务、现象和环境。</li><li>把多条转述当独立证据：检查原始链接与时间。</li><li>只看更新日志就认定已修复：当前版本实际复现。</li><li>用文档证明实现：分别记录预期与行为。</li><li>无法复现就删除问题：保留条件、范围和未知项。</li><li>将评论数量当发生率：需要明确总体和采样。</li><li>在笔记复制个人信息和长段原文：去标识并短摘录链接。</li><li>只收集负面资料：也检查成功、恢复与已修复证据。</li></ul><h2 id="可执行步骤" tabindex="-1">可执行步骤 <a class="header-anchor" href="#可执行步骤" aria-label="Permalink to &quot;可执行步骤&quot;">​</a></h2><ol><li>定义具体任务问题、版本与平台范围。</li><li>收集公开评价、Issue、官方文档和更新日志。</li><li>按任务、现象、环境、结果与恢复编码。</li><li>去重传播链，标记缺失字段和证据强度。</li><li>建立官方预期与当前实现双栏。</li><li>使用合成数据在当前版本复现主路径和失败分支。</li><li>补网络、日志、代码或总体数据验证机制与范围。</li><li>输出已确认、未复现、已修复和仍未知，不夸大结论。</li></ol><h2 id="练习与完成标准" tabindex="-1">练习与完成标准 <a class="header-anchor" href="#练习与完成标准" aria-label="Permalink to &quot;练习与完成标准&quot;">​</a></h2><p>选择一个公开产品的“同步失败”问题，建立证据包。</p><p>完成时应满足：</p><ul><li>至少包含评价、Issue、文档、更新日志中的三类资料；</li><li>每条记录有时间、版本、平台、任务和现象，缺失项明确；</li><li>去除个人信息，只保留必要短摘录与链接；</li><li>当前版本使用固定数据复现，并有失败分支；</li><li>区分本地保存、已上传、服务端处理和跨设备同步；</li><li>结论说明适用范围，不用资料数量估计发生率；</li><li>另一位读者能按验证任务重现结论。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.gov.uk/service-manual/helping-people-to-use-your-service/set-up-and-manage-user-support" target="_blank" rel="noreferrer">GOV.UK Service Manual：Set up and manage user support</a>（访问日期：2026-07-17）</li><li><a href="https://www.gov.uk/service-manual/measuring-success/using-data-to-improve-your-service-an-introduction" target="_blank" rel="noreferrer">GOV.UK Service Manual：Using performance data to improve your service</a>（访问日期：2026-07-17）</li><li><a href="https://www.gov.uk/service-manual/measuring-success/measuring-the-success-of-your-service" target="_blank" rel="noreferrer">GOV.UK Service Manual：Measuring the success of your service</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/test-evaluate/" target="_blank" rel="noreferrer">W3C WAI：Evaluating Web Accessibility Overview</a>（访问日期：2026-07-17）</li></ul>`,67)])])}const b=s(l,[["render",t]]);export{u as __pageData,b as default};
